#pragma once

struct FaxTabEntry
{
    u8 symbol;
    u8 nbits;
    u16 run;
};

// CCITT T.4/T.6 codeword classes
enum ccittSymbol : u8
{
    S_Null    = 0, // NOP / Invalid Entry
    S_Pass    = 1, // PASS mode (skip over region)
    S_Horiz   = 2, // HORIZONTAL MODE (explicit run lengths)
    S_V0      = 3, // VERTICAL 0 (no offsets, V0)
    S_VR      = 4, // VERTICAL RIGHT (offset +1, +2, +3, VR1..VR3)
    S_VL      = 5, // VERTICAL LEFT (offset -1, -2, -3, VL1..VL3)
    S_Ext     = 6, // Extension code
    S_TermW   = 7, // Terminating codes for White runs
    S_TermB   = 8, // Terminating codes for Black runs
    S_MakeUpW = 9, // Makeup codes for long White runs
    S_MakeUpB = 10, // Makeup codes for long Black runs
    S_MakeUp  = 11, // Generic makeup code
    S_EOL     = 12 // End of Line
};

